import { getWithFallback, patchWithFallback, postWithFallback } from './http';

export type CustomerStatus = 'Ativo' | 'Suspenso';
export type PaymentStatus = 'Em dia' | 'Atrasado';

export interface CustomerFinancial {
  monthlyFee: number;
  balanceDue: number;
  lastPaymentDate: string;
  paymentStatus: PaymentStatus;
}

export interface CustomerConnection {
  olt: string;
  ponPort: string;
  onuSerial: string;
  onuModel: string;
  rxPowerDbm: number;
  txPowerDbm: number;
  ipv4: string;
}

export interface Customer {
  id: string;
  name: string;
  email: string;
  phone: string;
  address: string;
  neighborhood: string;
  city: string;
  plan: string;
  status: CustomerStatus;
  financial: CustomerFinancial;
  connection: CustomerConnection;
}

export interface CreateCustomerInput {
  name: string;
  email: string;
  phone: string;
  address: string;
  neighborhood: string;
  city: string;
  plan: string;
  status: CustomerStatus;
  financial: CustomerFinancial;
  connection: CustomerConnection;
}

export interface UpdateCustomerInput {
  name: string;
  email: string;
  phone: string;
  address: string;
  neighborhood: string;
  city: string;
  plan: string;
  status: CustomerStatus;
  financial: CustomerFinancial;
  connection: CustomerConnection;
}

